import android.content.Intent
import android.net.Uri
import androidx.appcompat.app.AppCompatActivity
import java.util.regex.Pattern

class DeepLinkHandler(private val context: AppCompatActivity) {
    private val allowedHosts = arrayOf("myapp.com")
    private val allowedPaths = arrayOf("/profile", "/payment/confirm")

    fun handleDeepLink(uri: Uri?) {
        if (uri == null || !isValidUri(uri)) return

        val path = uri.path ?: ""
        val params = uri.queryParameters ?: HashMap<String, String>()

        when {
            isValidProfilePath(path) -> navigateToProfileActivity(params)
            isValidPaymentPath(path) -> navigateToPaymentActivity(params)
            else -> throw RuntimeException("Invalid deep link")
        }
    }

    private fun isValidUri(uri: Uri): Boolean {
        return uri.host in allowedHosts && (uri.path in allowedPaths || uri.path == "/")
    }

    private fun isValidProfilePath(path: String): Boolean {
        val pattern = Pattern.compile("/profile/\\d+")
        return pattern.matcher(path).find()
    }

    private fun isValidPaymentPath(path: String): Boolean {
        val pattern = Pattern.compile("/payment/confirm")
        return pattern.matcher(path).find()
    }

    private fun navigateToProfileActivity(params: Map<String, String>) {
        val id = params["id"] ?: ""
        if (id.isEmpty()) throw RuntimeException("Invalid profile ID")

        val intent = Intent(context, ProfileActivity::class.java)
        intent.putExtra("profileId", id)
